import org.owasp.encoder.Encode;

public class XssSecureCode {
    public static void main(String[] args) {
        // Simulating user input being received from an untrusted source (e.g., user input form)
        String userInput = "<script>alert('XSS Vulnerability')</script>";

        // Properly handling user input by encoding it before outputting it to the response
        System.out.println("<html>");
        System.out.println("<body>");
        System.out.println("<p>User Input: " + Encode.forHtml(userInput) + "</p>"); // Encoded user input
        System.out.println("</body>");
        System.out.println("</html>");
    }
}

